  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  { step: 1, title: "Account",  description: "Create your account"     },
  { step: 2, title: "Profile",  description: "Set up your profile"     },
  { step: 3, title: "Complete", description: "Review and confirm"      },
]

export default function StepperDemo() {
