  { step: 2, title: "Profile",  description: "Set up your profile"     },
  { step: 3, title: "Complete", description: "Review and confirm"      },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-2xl flex-col gap-8">
      {/* Stepper header */}
      <Stepper activeStep={activeStep} orientation="horizontal">
        {steps.map(({ step, title, description }) => (
          <React.Fragment key={step}>
            <StepperItem step={step} className="flex-col gap-1">
              <StepperTrigger onClick={() => setActiveStep(step)} />
              <StepperTitle>{title}</StepperTitle>
              <StepperDescription>{description}</StepperDescription>
            </StepperItem>
            {step < steps.length && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      {/* Step content panels */}
      <StepperContent step={1} activeStep={activeStep}>
        <p className="text-sm text-muted-foreground">
          Fill in your email and password to create your account.
        </p>
      </StepperContent>
      <StepperContent step={2} activeStep={activeStep}>
        <p className="text-sm text-muted-foreground">
          Add your name, bio, and profile picture.
        </p>
